import React, { useState, useRef, useEffect } from 'react';
import ReactDOM from 'react-dom';
import { Member, LabelType, FilterState } from '../../../types';

interface FilterBarProps {
  filter: FilterState;
  members: Member[];
  onFilterChange: (f: Partial<FilterState>) => void;
  onClear: () => void;
}

const LABELS: LabelType[] = ['Feature', 'Bug', 'Issue', 'Undefined'];
const DUE_OPTIONS = [
  { value: 'overdue', label: 'Overdue' },
  { value: 'today', label: 'Due Today' },
  { value: 'week', label: 'This Week' },
];

/* ───────────── ICONS ───────────── */
const IconUser = () => <span>👤</span>;
const IconTag = () => <span>🏷️</span>;
const IconCalendar = () => <span>📅</span>;
const IconChevronDown = () => <span>⌄</span>;
const IconX = () => <span>✕</span>;
const IconFilter = () => <span>⚙️</span>;
const CheckIcon = () => <span>✔</span>;

/* ───────────── PORTAL DROPDOWN ───────────── */
interface PortalDropdownProps {
  anchorRef: React.RefObject<HTMLElement>;
  open: boolean;
  onClose: () => void;
  children: React.ReactNode;
}

const PortalDropdown: React.FC<PortalDropdownProps> = ({
  anchorRef,
  open,
  onClose,
  children,
}) => {
  const dropdownRef = useRef<HTMLDivElement>(null);
  const [coords, setCoords] = useState({ top: 0, left: 0, width: 0 });

  useEffect(() => {
    if (!open || !anchorRef.current) return;
    const rect = anchorRef.current.getBoundingClientRect();
    setCoords({
      top: rect.bottom + 6,
      left: rect.left,
      width: rect.width,
    });
  }, [open]);

  // ✅ FIX OUTSIDE CLICK (portal-safe)
  useEffect(() => {
    if (!open) return;

    const handler = (e: MouseEvent) => {
      const target = e.target as Node;

      if (
        !anchorRef.current?.contains(target) &&
        !dropdownRef.current?.contains(target)
      ) {
        onClose();
      }
    };

    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open, onClose]);

  if (!open) return null;

  return ReactDOM.createPortal(
    <div
      ref={dropdownRef}
      style={{
        position: 'fixed',
        top: coords.top,
        left: coords.left,
        minWidth: Math.max(coords.width, 180),
        zIndex: 9999,
        background: 'white',
        border: '1px solid #ddd',
        borderRadius: 8,
        boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
        overflow: 'hidden',
      }}
    >
      {children}
    </div>,
    document.body
  );
};

/* ───────────── MAIN COMPONENT ───────────── */
export const FilterBar: React.FC<FilterBarProps> = ({
  filter,
  members,
  onFilterChange,
  onClear,
}) => {
  const [openMenu, setOpenMenu] = useState<'assignee' | 'label' | 'due' | null>(null);

  const assigneeRef = useRef<HTMLButtonElement>(null);
  const labelRef = useRef<HTMLButtonElement>(null);
  const dueRef = useRef<HTMLButtonElement>(null);

  const toggle = (menu: typeof openMenu) => {
    setOpenMenu(prev => (prev === menu ? null : menu));
  };

  const close = () => setOpenMenu(null);

  const hasFilter = filter.assigneeId || filter.label || filter.dueDate;

  const activeAssigneeName = filter.assigneeId
    ? members.find(m => m.id === filter.assigneeId)?.name
    : null;

  const activeDueLabel =
    DUE_OPTIONS.find(d => d.value === filter.dueDate)?.label ?? null;

  return (
    <div className="kb-filter-bar">

      <span className="kb-filter-bar__label">
        <IconFilter /> Filter
      </span>

      {/* ASSIGNEE */}
      <button ref={assigneeRef} onClick={() => toggle('assignee')}>
        <IconUser />
        {activeAssigneeName ?? 'Assignee'}
        {!filter.assigneeId && <IconChevronDown />}
      </button>

      <PortalDropdown
        anchorRef={assigneeRef}
        open={openMenu === 'assignee'}
        onClose={close}
      >
        <button onClick={() => { onFilterChange({ assigneeId: null }); close(); }}>
          All Members
        </button>

        {members.map(m => (
          <button
            key={m.id}
            onClick={() => {
              onFilterChange({ assigneeId: m.id });
              close();
            }}
          >
            {filter.assigneeId === m.id && <CheckIcon />}
            {m.name}
          </button>
        ))}
      </PortalDropdown>

      {/* LABEL */}
      <button ref={labelRef} onClick={() => toggle('label')}>
        <IconTag />
        {filter.label ?? 'Label'}
        {!filter.label && <IconChevronDown />}
      </button>

      <PortalDropdown
        anchorRef={labelRef}
        open={openMenu === 'label'}
        onClose={close}
      >
        <button onClick={() => { onFilterChange({ label: null }); close(); }}>
          All Labels
        </button>

        {LABELS.map(l => (
          <button
            key={l}
            onClick={() => {
              onFilterChange({ label: l });
              close();
            }}
          >
            {filter.label === l && <CheckIcon />}
            {l}
          </button>
        ))}
      </PortalDropdown>

      {/* DUE DATE */}
      <button ref={dueRef} onClick={() => toggle('due')}>
        <IconCalendar />
        {activeDueLabel ?? 'Due Date'}
        {!filter.dueDate && <IconChevronDown />}
      </button>

      <PortalDropdown
        anchorRef={dueRef}
        open={openMenu === 'due'}
        onClose={close}
      >
        <button onClick={() => { onFilterChange({ dueDate: null }); close(); }}>
          Any Date
        </button>

        {DUE_OPTIONS.map(d => (
          <button
            key={d.value}
            onClick={() => {
              onFilterChange({ dueDate: d.value as any });
              close();
            }}
          >
            {filter.dueDate === d.value && <CheckIcon />}
            {d.label}
          </button>
        ))}
      </PortalDropdown>

      {/* CLEAR */}
      {hasFilter && (
        <button onClick={onClear}>
          <IconX /> Clear
        </button>
      )}
    </div>
  );
};
